request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?caseName ?caseNodeName ?edge ?guardName WHERE {
  ?acq rdf:type vocab:activity .
  ?acq vocab:NamedElement_name ?acqName .
  FILTER(?acqName = "Acquire%20and%20Guide" || ?acqName = "Acquire")

  ?edge rdf:type vocab:Activity_edge .
  ?edge vocab:Activity_edge_source ?src .
  ?edge vocab:Activity_edge_target ?tgt .

  # guard/decision information (may be stored as a ValueSpecification/Expression)
  OPTIONAL {
    ?edge vocab:Activity_edge_guard ?guard .
    OPTIONAL { ?guard vocab:NamedElement_name ?guardName . }
    OPTIONAL { ?src vocab:NamedElement_name ?caseNodeName . }
    BIND(COALESCE(?guardName, ?caseNodeName) AS ?caseName)
  }

  # fallback: if the edge itself has a name
  OPTIONAL {
    ?edge vocab:NamedElement_name ?edgeName .
    BIND(COALESCE(?caseName, ?edgeName) AS ?caseName)
  }

  FILTER(
    (BOUND(?guardName) && (
      CONTAINS(LCASE(STR(?guardName)), LCASE("guide")) ||
      CONTAINS(LCASE(STR(?guardName)), LCASE("star"))
    ))
    ||
    (BOUND(?caseNodeName) && (
      CONTAINS(LCASE(STR(?caseNodeName)), LCASE("guide")) ||
      CONTAINS(LCASE(STR(?caseNodeName)), LCASE("star"))
    ))
    ||
    (BOUND(?edgeName) && (
      CONTAINS(LCASE(STR(?edgeName)), LCASE("guide")) ||
      CONTAINS(LCASE(STR(?edgeName)), LCASE("star"))
    ))
  )

}
LIMIT 25
